), inserted as (
  insert into public.mdr_students (
    student_id, name, guardian_name, guardian_phone, guardian_occupation, district, upazila,
    division_id, current_class_id, current_roll, admission_date, hijri_year, status,
    is_waqf, is_hifz, import_source, old_student_id
  )
  select i.student_id, i.name, i.guardian_name, i.guardian_phone, i.guardian_occupation, i.district, i.upazila,
    d.id, c.id, i.current_roll, current_date, i.hijri_year, 'active', false, false, i.import_source, i.old_student_id
  from incoming i
  join public.mdr_divisions d on d.code = i.division_code
  join public.mdr_classes c on c.code = i.class_code and c.division_id = d.id
  returning id, current_class_id, current_roll
)
insert into public.mdr_class_history (student_id, class_id, roll, from_date, notes)
select id, current_class_id, current_roll, current_date, 'Imported from 1447-48 Excel files'
from inserted;

